mapper.select:
SELECT a.id ,a.violation_id as violationId, a.instance_id as instanceId, v.code, v.order_id as orderId,v.staff_id as staffId , v.name
,v.gender, v.is_cooker as cooker,v.status as violationStatus,
v.position , v.phone, v.happen_time as happenTime, v.service_time as serviceTime,v.type,v.score,
v.total_amount as totalAmount, v.pay_status as payStatus, a.status,v.city_name as cityName,v.city_code as
cityCode, v.department,
v.site_name as siteName,v.site_id as siteId,v.site_leader_id as siteLeaderId, v.site_leader_name as
siteLeaderName, v.site_leader_work_num as siteLeaderWorkNum,
v.site_leader_phone as siteLeaderPhone,v.deadline_time as deadlineTime,a.create_by as createBy,a.create_time as
createTime, v.deduct_type as deductType, v.detail,
a.modify_by as modifyBy, a.modify_time as modifyTime,v.employment_type as workType
from appeal a LEFT JOIN violation v on a.violation_id=v.id

where 1 = 1


    AND a.status = #{status}



    AND v.status = #{violationStatus}



    AND v.pay_status = #{payStatus}


    AND v.position = #{position}



    AND v.code = #{code}



    AND v.staff_id = #{staffId}



    AND v.order_id = #{orderId}



    AND v.city_code = #{cityCode}



    AND v.site_id in

        #{siteIds[${index}],jdbcType=BIGINT}




    AND v.type = #{type}



    AND v.deduct_type = #{deductType}


    AND v.detail = #{detail}



    AND v.department = #{department}



    AND v.happen_time >= #{startHappenTime}



    AND v.happen_time <= #{endHappenTime}



    AND v.service_time >= #{startServiceTime}


    AND v.service_time <= #{endServiceTime}


order by a.create_time DESC
